import React from 'react';
import ImageSlider from '../../../../elements/imageSlider/ImageSlider';

const images=[
    '/images/blog/post_2/banner.jpg',
    '/images/blog/post_2/img1.jpg',
    '/images/blog/post_2/img2.jpg',
    '/images/blog/post_2/flyback.png'
]

const videoSrcs=[
    'https://www.youtube.com/embed/GnIX9K6eFeM',
    'https://www.youtube.com/embed/OUjGYnrEkSw',
    'https://www.youtube.com/embed/HCWHFp4Kk3Y'
]

const BlogPost_TR_2 = () => (
    <div>
        <div className='row g-4 my-4'>
            {videoSrcs.map((videoSrc,index)=>
                <div key={index} className='col-12 col-md-6 col-lg-4'>
                    <div className='ratio' style={{ '--bs-aspect-ratio': '177.78%' }}>
                        <iframe src={videoSrc} title="CNC Milling Machine" frameborder="0" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" referrerpolicy="strict-origin-when-cross-origin" allowfullscreen></iframe>
                    </div>
                </div>
            )}
        </div>
        <p>Pano yerleşimi, muhtemel manyetik alan problemlerinin çözümü, analog kontaktlar ve spindle gibi ark ve voltaj dalgalanmasi yaratan sistemlerin izolasyonu.</p>
        <ImageSlider images={images} imageSources={images} interval={3000} />
    </div>
)

export default BlogPost_TR_2
